import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isLanding = location.pathname === '/';

  return (
    <nav style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      zIndex: 100,
      padding: '0 32px',
      height: '64px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      background: scrolled ? 'rgba(247, 244, 238, 0.92)' : 'transparent',
      backdropFilter: scrolled ? 'blur(12px)' : 'none',
      borderBottom: scrolled ? '1px solid rgba(26,26,24,0.08)' : '1px solid transparent',
      transition: 'all 0.3s ease',
    }}>
      {/* Logo */}
      <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none' }}>
        <div style={{
          width: '32px',
          height: '32px',
          background: 'var(--green)',
          borderRadius: '10px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}>
          <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
            <path d="M9 2C9 2 5 5 5 9.5C5 12 6.5 14 9 14C11.5 14 13 12 13 9.5C13 5 9 2 9 2Z" fill="white" fillOpacity="0.9"/>
            <path d="M6 11C7 12.5 8 13 9 13" stroke="white" strokeWidth="1.5" strokeLinecap="round" opacity="0.6"/>
          </svg>
        </div>
        <span style={{
          fontFamily: 'var(--font-display)',
          fontSize: '20px',
          color: 'var(--ink)',
          letterSpacing: '-0.02em',
        }}>V-Fit</span>
      </Link>

      {/* Nav links (landing only) */}
      {isLanding && (
        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          {['Features', 'How it Works', 'About'].map(item => (
            <a
              key={item}
              href={`#${item.toLowerCase().replace(/\s+/g, '-')}`}
              className="btn btn-ghost"
              style={{ fontSize: '14px' }}
            >
              {item}
            </a>
          ))}
        </div>
      )}

      {/* Auth buttons */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
        <Link to="/login" className="btn btn-ghost" style={{ fontSize: '14px' }}>
          Log in
        </Link>
        <Link to="/register" className="btn btn-primary" style={{ fontSize: '14px' }}>
          Get started
        </Link>
      </div>
    </nav>
  );
}
